<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Conway's Game of Life</title>
  <style>
    * {
      margin: 0;
      padding: 0;
      box-sizing: border-box;
    }

    body {
      background: #1a1a1a;
      color: #e0e0e0;
      font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
      display: flex;
      flex-direction: column;
      align-items: center;
      justify-content: center;
      min-height: 100vh;
      padding: 20px;
    }

    h1 {
      margin-bottom: 20px;
      font-size: 2.5em;
      text-shadow: 0 0 10px rgba(0, 255, 127, 0.5);
      letter-spacing: 2px;
    }

    .container {
      display: flex;
      flex-direction: column;
      align-items: center;
      gap: 20px;
    }

    #life {
      border: 3px solid #00ff7f;
      background: #0a0a0a;
      cursor: crosshair;
      box-shadow: 0 0 30px rgba(0, 255, 127, 0.4), inset 0 0 20px rgba(0, 0, 0, 0.5);
      image-rendering: pixelated;
      image-rendering: -moz-crisp-edges;
      image-rendering: crisp-edges;
      display: block;
    }

    .controls {
      display: flex;
      gap: 12px;
      flex-wrap: wrap;
      justify-content: center;
    }

    button {
      padding: 12px 24px;
      font-size: 1em;
      background: linear-gradient(135deg, #00ff7f, #00dd6f);
      color: #000;
      border: none;
      border-radius: 6px;
      cursor: pointer;
      font-weight: bold;
      transition: all 0.2s;
      box-shadow: 0 4px 12px rgba(0, 255, 127, 0.3);
    }

    button:hover {
      background: linear-gradient(135deg, #00dd6f, #00bb5f);
      transform: translateY(-2px);
      box-shadow: 0 6px 20px rgba(0, 255, 127, 0.5);
    }

    button:active {
      transform: translateY(0);
      box-shadow: 0 2px 8px rgba(0, 255, 127, 0.3);
    }

    button.playing {
      background: linear-gradient(135deg, #ff6b6b, #ff5252);
      box-shadow: 0 4px 12px rgba(255, 107, 107, 0.3);
    }

    button.playing:hover {
      background: linear-gradient(135deg, #ff5252, #ff3030);
      box-shadow: 0 6px 20px rgba(255, 107, 107, 0.5);
    }

    .info {
      font-size: 0.9em;
      color: #666;
      margin-top: 10px;
      text-align: center;
    }
  </style>
</head>
<body>
  <h1>🧬 Game of Life</h1>
  <div class="container">
    <canvas id="life" width="400" height="400"></canvas>
    <div class="controls">
      <button id="step">▶ Step</button>
      <button id="play">⏵ Play</button>
      <button id="random">🎲 Random</button>
      <button id="clear">🗑 Clear</button>
    </div>
    <div class="info">
      Click and drag to paint cells • 10 generations/sec when playing
    </div>
  </div>

  <script>
    const GRID_WIDTH = 50;
    const GRID_HEIGHT = 50;
    const CELL_SIZE = 8;
    const SPEED = 100;

    const canvas = document.getElementById('life');
    const ctx = canvas.getContext('2d');
    const stepBtn = document.getElementById('step');
    const playBtn = document.getElementById('play');
    const randomBtn = document.getElementById('random');
    const clearBtn = document.getElementById('clear');

    let grid = new Array(GRID_HEIGHT * GRID_WIDTH).fill(0);
    let isPlaying = false;
    let isDrawing = false;

    window.life = {
      w: GRID_WIDTH,
      h: GRID_HEIGHT,
      get(x, y) {
        if (x < 0 || x >= GRID_WIDTH || y < 0 || y >= GRID_HEIGHT) return 0;
        return grid[y * GRID_WIDTH + x];
      },
      set(x, y, v) {
        if (x >= 0 && x < GRID_WIDTH && y >= 0 && y < GRID_HEIGHT) {
          grid[y * GRID_WIDTH + x] = v ? 1 : 0;
        }
      },
      step() {
        computeNextGeneration();
        render();
      },
      clear() {
        grid.fill(0);
        render();
      }
    };

    function countNeighbours(x, y) {
      let count = 0;
      for (let dx = -1; dx <= 1; dx++) {
        for (let dy = -1; dy <= 1; dy++) {
          if (dx === 0 && dy === 0) continue;
          const nx = x + dx;
          const ny = y + dy;
          if (nx >= 0 && nx < GRID_WIDTH && ny >= 0 && ny < GRID_HEIGHT) {
            count += grid[ny * GRID_WIDTH + nx];
          }
        }
      }
      return count;
    }

    function computeNextGeneration() {
      const nextGrid = new Array(GRID_HEIGHT * GRID_WIDTH).fill(0);

      for (let y = 0; y < GRID_HEIGHT; y++) {
        for (let x = 0; x < GRID_WIDTH; x++) {
          const idx = y * GRID_WIDTH + x;
          const alive = grid[idx];
          const neighbours = countNeighbours(x, y);

          if (alive) {
            nextGrid[idx] = (neighbours === 2 || neighbours === 3) ? 1 : 0;
          } else {
            nextGrid[idx] = neighbours === 3 ? 1 : 0;
          }
        }
      }

      grid = nextGrid;
    }

    function render() {
      ctx.fillStyle = '#0a0a0a';
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      ctx.fillStyle = '#00ff7f';
      for (let y = 0; y < GRID_HEIGHT; y++) {
        for (let x = 0; x < GRID_WIDTH; x++) {
          if (grid[y * GRID_WIDTH + x]) {
            ctx.fillRect(x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE - 1, CELL_SIZE - 1);
          }
        }
      }
    }

    function seedRandom() {
      for (let i = 0; i < grid.length; i++) {
        grid[i] = Math.random() > 0.7 ? 1 : 0;
      }
      render();
    }

    function togglePlay() {
      if (isPlaying) {
        isPlaying = false;
        playBtn.textContent = '⏵ Play';
        playBtn.classList.remove('playing');
      } else {
        isPlaying = true;
        playBtn.textContent = '⏸ Pause';
        playBtn.classList.add('playing');
        scheduleNextStep();
      }
    }

    function scheduleNextStep() {
      if (!isPlaying) return;
      window.life.step();
      setTimeout(scheduleNextStep, SPEED);
    }

    canvas.addEventListener('mousedown', () => {
      isDrawing = true;
    });

    canvas.addEventListener('mousemove', (e) => {
      if (isDrawing) {
        toggleCell(e);
      }
    });

    canvas.addEventListener('mouseup', () => {
      isDrawing = false;
    });

    canvas.addEventListener('mouseleave', () => {
      isDrawing = false;
    });

    function toggleCell(e) {
      const rect = canvas.getBoundingClientRect();
      const x = Math.floor((e.clientX - rect.left) / CELL_SIZE);
      const y = Math.floor((e.clientY - rect.top) / CELL_SIZE);

      if (x >= 0 && x < GRID_WIDTH && y >= 0 && y < GRID_HEIGHT) {
        const idx = y * GRID_WIDTH + x;
        grid[idx] = grid[idx] ? 0 : 1;
        render();
      }
    }

    stepBtn.addEventListener('click', () => {
      if (isPlaying) togglePlay();
      window.life.step();
    });

    playBtn.addEventListener('click', togglePlay);
    randomBtn.addEventListener('click', seedRandom);
    clearBtn.addEventListener('click', () => {
      if (isPlaying) togglePlay();
      window.life.clear();
    });

    render();
  </script>
</body>
</html>
